import { NextRequest, NextResponse } from 'next/server';
import { generateComponent } from '@/lib/ai/componentGenerator';
import type { GenerationMode } from '@/lib/ai/componentGenerator';
import { validateAccessibility, autoRepairA11y } from '@/lib/validation/a11yValidator';
import { generateTests } from '@/lib/testGenerator';
import { saveGeneration, getProjectById } from '@/lib/ai/memory';
import { UIIntentSchema } from '@/lib/validation/schemas';

export async function POST(request: NextRequest) {
  try {
    let body: unknown;
    try {
      body = await request.json();
    } catch {
      return NextResponse.json(
        { success: false, error: 'Invalid JSON in request body' },
        { status: 400 }
      );
    }

    if (!body || typeof body !== 'object' || !('intent' in body)) {
      return NextResponse.json(
        { success: false, error: 'Missing required field: intent' },
        { status: 400 }
      );
    }

    // Validate intent shape with Zod
    const intentValidation = UIIntentSchema.safeParse((body as { intent: unknown }).intent);
    if (!intentValidation.success) {
      return NextResponse.json(
        {
          success: false,
          error: `Invalid intent structure: ${intentValidation.error.issues.map(i => i.message).join(', ')}`,
        },
        { status: 400 }
      );
    }

    const intent = intentValidation.data;
    const { mode, model, maxTokens, isMultiSlide } = body as { mode?: string; model?: string; maxTokens?: number; isMultiSlide?: boolean };
    const generationMode: GenerationMode = mode === 'app' ? 'app' : mode === 'webgl' ? 'webgl' : 'component';

    if (!process.env.OPENAI_API_KEY) {
      return NextResponse.json(
        { success: false, error: 'OPENAI_API_KEY is not configured. Add it to your .env.local file.' },
        { status: 500 }
      );
    }

    // Step 0: Handle Refinement Context
    let refinementContext: { code: string; manifest?: any } | undefined;
    if (intent.isRefinement && intent.previousProjectId) {
      const parentProject = getProjectById(intent.previousProjectId);
      if (parentProject) {
        // Find the specific file to refine if targetFiles is provided, 
        // otherwise default to the first file or the full component string
        let targetCode: string;
        if (typeof parentProject.code === 'string') {
          targetCode = parentProject.code;
        } else {
          const targetFile = intent.targetFiles?.[0] || Object.keys(parentProject.code)[0];
          targetCode = parentProject.code[targetFile] || Object.values(parentProject.code)[0];
        }

        refinementContext = {
          code: targetCode,
          manifest: parentProject.manifest
        };
      }
    }

    // Step 1: Generate component/app code
    const generationResult = await generateComponent(
      intent, 
      generationMode, 
      model, 
      maxTokens, 
      isMultiSlide,
      refinementContext
    );
    if (!generationResult.success || !generationResult.code) {
      return NextResponse.json(
        { success: false, error: generationResult.error },
        { status: 422 }
      );
    }

    const code = generationResult.code;

    // Step 2 & 5: Parallel Logic (A11y + Tests)
    const [a11yResult, tests] = await Promise.all([
      // A11y Flow
      (async () => {
        const initialReport = validateAccessibility(code);
        let finalCode = code;
        let appliedFixes: string[] = [];

        if (!initialReport.passed) {
          const repaired = autoRepairA11y(code);
          finalCode = repaired.code;
          appliedFixes = repaired.appliedFixes;
        }

        const finalReport = appliedFixes.length > 0
          ? validateAccessibility(finalCode)
          : initialReport;

        return { finalCode, finalReport, appliedFixes };
      })(),
      // Test Generation Flow (uses initial code for speed, repairs are usually minor)
      (async () => {
        return generateTests(intent, code);
      })()
    ]);

    const { finalCode, finalReport, appliedFixes } = a11yResult;

    // Step 6: Save to memory (async)
    if (generationMode === 'app' || (generationMode === 'component' && finalReport.passed && finalReport.score >= 80)) {
      setTimeout(() => {
        saveGeneration(
          intent, 
          finalCode, 
          finalReport.score, 
          undefined,
          intent.previousProjectId
        );
      }, 0);
    }

    return NextResponse.json({
      success: true,
      code: finalCode,
      a11yReport: {
        ...finalReport,
        appliedFixes,
      },
      tests,
      mode: generationMode,
    });
  } catch (error) {
    console.error('[/api/generate] Unexpected error:', error);
    return NextResponse.json(
      { success: false, error: 'Internal server error' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import fs from 'fs';
import path from 'path';
import { getProjectById } from '@/lib/ai/memory';

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const id = searchParams.get('id');

    if (id) {
      const project = getProjectById(id);
      if (!project) {
        return NextResponse.json({ success: false, error: 'Project not found' }, { status: 404 });
      }
      return NextResponse.json({ success: true, project });
    }

    const MEMORY_FILE_PATH = path.join(process.cwd(), 'data', 'history.json');
    if (!fs.existsSync(MEMORY_FILE_PATH)) {
      return NextResponse.json({ history: [] });
    }

    const data = fs.readFileSync(MEMORY_FILE_PATH, 'utf-8');
    const parsed = JSON.parse(data);

    // We don't want to send the entire raw code blocks over the wire just for a history list,
    // so we map it out to lightweight summary chips
    const summarizedHistory = parsed.map((entry: any) => ({
      id: entry.id,
      timestamp: entry.timestamp,
      componentType: entry.componentType,
      componentName: entry.componentName,
      promptSnippet: entry.intent.description.length > 60 
        ? entry.intent.description.substring(0, 60) + '...' 
        : entry.intent.description
    }));

    return NextResponse.json({ history: summarizedHistory });
  } catch (error) {
    console.error('Failed to parse history JSON:', error);
    return NextResponse.json({ history: [] });
  }
}

import { NextResponse } from 'next/server';
import OpenAI from 'openai';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

export async function POST(req: Request) {
  if (!process.env.OPENAI_API_KEY) {
    return NextResponse.json({ error: 'OPENAI_API_KEY is not configured.' }, { status: 500 });
  }

  try {
    const formData = await req.formData();
    const imageFile = formData.get('image') as File | null;

    if (!imageFile) {
      return NextResponse.json({ error: 'No image uploaded' }, { status: 400 });
    }

    const arrayBuffer = await imageFile.arrayBuffer();
    const buffer = Buffer.from(arrayBuffer);
    const base64Image = buffer.toString('base64');
    const mimeType = imageFile.type;
    const dataUrl = `data:${mimeType};base64,${base64Image}`;

    const response = await openai.chat.completions.create({
      model: 'gpt-4o',
      messages: [
        {
          role: 'user',
          content: [
            { type: 'text', text: 'Analyze this image and describe the UI components, layout, and purpose shown. Keep it concise but highly descriptive so it can be used to generate a matching React component.' },
            { type: 'image_url', image_url: { url: dataUrl } },
          ],
        },
      ],
      max_tokens: 300,
    });

    const caption = response.choices[0]?.message?.content || 'An uploaded image';
    return NextResponse.json({ caption });

  } catch (error: any) {
    console.error('Image to Text error:', error);
    return NextResponse.json(
      { error: error?.message || 'Failed to process image with OpenAI Vision.' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { generateAppManifest } from '@/lib/ai/chunkGenerator';
import { UIIntentSchema } from '@/lib/validation/schemas';

export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { intent, model, isMultiSlide } = body;

    if (!intent || !model) {
      return NextResponse.json({ success: false, error: 'Missing intent or model' }, { status: 400 });
    }

    const manifest = await generateAppManifest(intent, model, isMultiSlide);
    return NextResponse.json({ success: true, manifest });
  } catch (error) {
    console.error('[/api/manifest] Error:', error);
    return NextResponse.json({ success: false, error: 'Manifest generation failed' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { parseIntent } from '@/lib/ai/intentParser';
import type { GenerationMode } from '@/lib/ai/componentGenerator';

const MAX_INPUT_LENGTH = 20000;

export async function POST(request: NextRequest) {
  try {
    let body: unknown;
    try {
      body = await request.json();
    } catch {
      return NextResponse.json(
        { success: false, error: 'Invalid JSON in request body' },
        { status: 400 }
      );
    }

    if (!body || typeof body !== 'object' || !('prompt' in body)) {
      return NextResponse.json(
        { success: false, error: 'Missing required field: prompt' },
        { status: 400 }
      );
    }

    const { prompt, mode, contextId, model } = body as {
      prompt: string;
      mode: GenerationMode;
      contextId?: string;
      model?: string;
    };

    if (typeof prompt !== 'string') {
      return NextResponse.json(
        { success: false, error: 'prompt must be a string' },
        { status: 400 }
      );
    }

    if (prompt.trim().length === 0) {
      return NextResponse.json(
        { success: false, error: 'prompt cannot be empty' },
        { status: 400 }
      );
    }

    if (prompt.length > MAX_INPUT_LENGTH) {
      return NextResponse.json(
        { success: false, error: 'Your prompt is too long and detailed. Please provide a more concise description.' },
        { status: 400 }
      );
    }

    if (!process.env.OPENAI_API_KEY) {
      return NextResponse.json(
        { success: false, error: 'OPENAI_API_KEY is not configured. Add it to your .env.local file.' },
        { status: 500 }
      );
    }

    const generationMode: GenerationMode = mode === 'app' ? 'app' : mode === 'webgl' ? 'webgl' : 'component';
    const result = await parseIntent(prompt, generationMode, typeof contextId === 'string' ? contextId : undefined);

    if (!result.success) {
      return NextResponse.json(
        { success: false, error: result.error },
        { status: 422 }
      );
    }

    return NextResponse.json({
      success: true,
      intent: result.intent,
    });
  } catch (error) {
    console.error('[/api/parse] Unexpected error:', error);
    return NextResponse.json(
      { success: false, error: 'Internal server error' },
      { status: 500 }
    );
  }
}

