'use client';

import React, { useState, useEffect, useRef } from 'react';
import { ChevronDown, Check, Settings2, ShieldAlert, Layers } from 'lucide-react';

export type AIModel = 'gpt-5.4-nano' | 'gpt-5.4-mini' | 'gpt-4.1' | 'gpt-5.4' | 'gpt-4o';

export interface ModelDef {
  id: AIModel;
  name: string;
  description: string;
  icon: string;
  maxLines: number;
}

export const AI_MODELS: Record<AIModel, ModelDef> = {
  'gpt-5.4-mini': { id: 'gpt-5.4-mini', name: 'GPT-5.4 Mini', description: 'Daily UI generation', icon: '⚡', maxLines: 500 },
  'gpt-5.4-nano': { id: 'gpt-5.4-nano', name: 'GPT-5.4 Nano', description: 'Ultra-fast', icon: '⚡', maxLines: 250 },
  'gpt-4.1': { id: 'gpt-4.1', name: 'GPT-4.1', description: 'Massive context', icon: '📦', maxLines: 500 },
  'gpt-5.4': { id: 'gpt-5.4', name: 'GPT-5.4', description: 'Advanced reasoning', icon: '🧠', maxLines: 1000 },
  'gpt-4o': { id: 'gpt-4o', name: 'GPT-4o', description: 'Multimodal', icon: '🖼️', maxLines: 500 },
};

interface ModelSwitcherProps {
  onModelChange: (model: AIModel) => void;
  onFullAppModeChange: (enabled: boolean) => void;
  onMultiSlideModeChange: (enabled: boolean) => void;
  disabled?: boolean;
}

export default function ModelSwitcher({ onModelChange, onFullAppModeChange, onMultiSlideModeChange, disabled }: ModelSwitcherProps) {
  const [selectedModel, setSelectedModel] = useState<AIModel>('gpt-5.4-mini');
  const [isFullAppMode, setIsFullAppMode] = useState(false);
  const [isMultiSlideMode, setIsMultiSlideMode] = useState(false);
  const [isOpen, setIsOpen] = useState(false);
  const [toastMessage, setToastMessage] = useState<string | null>(null);

  const dropdownRef = useRef<HTMLDivElement>(null);

  // Load from localStorage on mount
  useEffect(() => {
    try {
      const savedModel = localStorage.getItem('uiEngine_model') as AIModel | null;
      const savedAppMode = localStorage.getItem('uiEngine_fullAppMode');
      const savedSlideMode = localStorage.getItem('uiEngine_multiSlideMode');

      if (savedModel && AI_MODELS[savedModel]) {
        setSelectedModel(savedModel);
        onModelChange(savedModel);
      }
      if (savedAppMode) {
        const isEnabled = savedAppMode === 'true';
        setIsFullAppMode(isEnabled);
        onFullAppModeChange(isEnabled);
      }
      if (savedSlideMode) {
        const isEnabled = savedSlideMode === 'true';
        setIsMultiSlideMode(isEnabled);
        onMultiSlideModeChange(isEnabled);
      }
    } catch (e) {
      console.warn("LocalStorage access denied or unavailable", e);
    }
  }, []);

  // Close dropdown on outside click
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const showToast = (message: string) => {
    setToastMessage(message);
    setTimeout(() => setToastMessage(null), 3000);
  };

  const handleSelectModel = (modelId: AIModel) => {
    setSelectedModel(modelId);
    setIsOpen(false);
    localStorage.setItem('uiEngine_model', modelId);
    onModelChange(modelId);
    showToast(`Switched to ${AI_MODELS[modelId].name}`);
  };

  const handleToggleFullAppMode = () => {
    const newVal = !isFullAppMode;
    setIsFullAppMode(newVal);
    localStorage.setItem('uiEngine_fullAppMode', String(newVal));
    onFullAppModeChange(newVal);
    showToast(newVal ? 'Full App Mode Enabled (Chunking)' : 'Full App Mode Disabled');
  };

  const handleToggleMultiSlideMode = () => {
    const newVal = !isMultiSlideMode;
    setIsMultiSlideMode(newVal);
    localStorage.setItem('uiEngine_multiSlideMode', String(newVal));
    onMultiSlideModeChange(newVal);
    showToast(newVal ? 'Multi-Slide Mode Enabled' : 'Multi-Slide Mode Disabled');
  };

  const activeModel = AI_MODELS[selectedModel];

  return (
    <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-4 relative" ref={dropdownRef}>

      {/* Toast Notification */}
      {toastMessage && (
        <div className="absolute -top-12 left-1/2 -translate-x-1/2 px-4 py-2 bg-blue-600 text-white text-xs font-semibold rounded-lg shadow-lg z-50 whitespace-nowrap animate-in fade-in slide-in-from-bottom-2">
          {toastMessage}
        </div>
      )}

      {/* Model Dropdown Container */}
      <div className="relative flex-1 sm:min-w-[240px]">
        <button
          type="button"
          disabled={disabled}
          onClick={() => setIsOpen(!isOpen)}
          aria-haspopup="listbox"
          aria-expanded={isOpen}
          className="w-full flex items-center justify-between gap-3 px-4 py-2 bg-gray-900 border border-gray-700/50 rounded-xl hover:bg-gray-800 transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:opacity-50 disabled:cursor-not-allowed group"
        >
          <div className="flex items-center gap-3 truncate">
            <span className="text-xl" aria-hidden="true">{activeModel.icon}</span>
            <div className="flex flex-col items-start truncate">
              <span className="text-sm font-semibold text-white truncate">{activeModel.name}</span>
              <span className="text-[10px] text-gray-400 truncate hidden sm:block">Up to {activeModel.maxLines} lines</span>
            </div>
          </div>
          <ChevronDown className={`w-4 h-4 text-gray-400 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
        </button>

        {isOpen && (
          <div
            role="listbox"
            className="absolute top-full left-0 w-full mt-2 bg-gray-900 border border-gray-700 rounded-xl shadow-2xl z-40 py-2"
          >
            {Object.values(AI_MODELS).map((model) => (
              <button
                key={model.id}
                role="option"
                aria-selected={selectedModel === model.id}
                onClick={() => handleSelectModel(model.id)}
                className="w-full flex items-center justify-between px-4 py-3 hover:bg-gray-800 transition-colors text-left"
              >
                <div className="flex items-center gap-3">
                  <span className="text-xl">{model.icon}</span>
                  <div className="flex flex-col">
                    <span className="text-sm font-semibold text-white">{model.name}</span>
                    <span className="text-xs text-gray-400">{model.description} · Limit: {model.maxLines}</span>
                  </div>
                </div>
                {selectedModel === model.id && <Check className="w-4 h-4 text-blue-500" />}
              </button>
            ))}
          </div>
        )}
      </div>

      {/* Right Controls Container */}
      <div className="flex items-center gap-2 ml-auto">

        {/* Full App Mode Toggle */}
        <div className="flex items-center gap-2 px-3 py-1.5 bg-gray-900/40 border border-gray-700/30 rounded-xl">
          <div className="flex flex-col items-end sm:items-start group relative">
            <label htmlFor="full-app-toggle" className="text-sm font-semibold text-white flex items-center gap-2 cursor-pointer">
              <Settings2 className="w-4 h-4 text-gray-400" />
              Full App
            </label>
            <span className="text-[10px] text-gray-500 hidden sm:block">Chunking mode</span>

            {/* Tooltip */}
            <div className="absolute bottom-full mb-2 left-1/2 -translate-x-1/2 w-48 p-2 bg-gray-800 text-xs text-gray-300 rounded shadow-lg opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-50">
              Bypasses API token limits by generating deep architectural file manifests and chunking generation.
            </div>
          </div>

          <button
            id="full-app-toggle"
            role="switch"
            aria-checked={isFullAppMode}
            disabled={disabled}
            onClick={handleToggleFullAppMode}
            className={`relative inline-flex h-5 w-9 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 focus:ring-offset-gray-900 ${
              isFullAppMode ? 'bg-violet-600' : 'bg-gray-700'
            } disabled:opacity-50 disabled:cursor-not-allowed`}
          >
            <span
              className={`inline-block h-3 w-3 transform rounded-full bg-white transition-transform ${
                isFullAppMode ? 'translate-x-5' : 'translate-x-1'
              }`}
            />
          </button>
        </div>

        {/* Multi-Slide Mode Toggle */}
        <div className="flex items-center gap-2 px-3 py-1.5 bg-gray-900/40 border border-gray-700/30 rounded-xl">
          <div className="flex flex-col items-end sm:items-start group relative">
            <label htmlFor="multi-slide-toggle" className="text-sm font-semibold text-white flex items-center gap-2 cursor-pointer">
              <Layers className="w-4 h-4 text-gray-400" />
              Multi-slide
            </label>
            <span className="text-[10px] text-gray-500 hidden sm:block">Paginated view</span>

            {/* Tooltip */}
            <div className="absolute bottom-full right-0 mb-2 w-56 p-2 bg-gray-800 text-[11px] leading-tight text-gray-300 rounded shadow-xl opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-50">
              Instructs the AI to structuralize outputs as a multi-slide/multi-view architectural experience rather than a single static block. For WebGL, orchestrates camera physics with HTML navigation overlays.
            </div>
          </div>

          <button
            id="multi-slide-toggle"
            role="switch"
            aria-checked={isMultiSlideMode}
            disabled={disabled}
            onClick={handleToggleMultiSlideMode}
            className={`relative inline-flex h-5 w-9 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 focus:ring-offset-gray-900 ${
              isMultiSlideMode ? 'bg-emerald-500' : 'bg-gray-700'
            } disabled:opacity-50 disabled:cursor-not-allowed`}
          >
            <span
              className={`inline-block h-3 w-3 transform rounded-full bg-white transition-transform ${
                isMultiSlideMode ? 'translate-x-5' : 'translate-x-1'
              }`}
            />
          </button>
        </div>

      </div>
    </div>
  );
}

'use client';

import React from 'react';
import {
  CheckCircle, Circle, Loader2, AlertCircle,
  Brain, Code2, ShieldCheck, TestTube, Eye, Zap,
} from 'lucide-react';

export type PipelineStep =
  | 'idle'
  | 'parsing'
  | 'parsed'
  | 'generating'
  | 'validating'
  | 'testing'
  | 'complete'
  | 'error';

interface Step {
  id: string;
  label: string;
  description: string;
  icon: React.ReactNode;
  activeStep: PipelineStep;
  completedSteps: PipelineStep[];
}

interface PipelineStatusProps {
  currentStep: PipelineStep;
  errorMessage?: string;
}

const STEPS: Step[] = [
  {
    id: 'parse',
    label: 'Intent Parser',
    description: 'Converting NL to structured JSON',
    icon: <Brain className="w-4 h-4" />,
    activeStep: 'parsing',
    completedSteps: ['parsed', 'generating', 'validating', 'testing', 'complete'],
  },
  {
    id: 'generate',
    label: 'Code Generator',
    description: 'Building React + TypeScript component',
    icon: <Code2 className="w-4 h-4" />,
    activeStep: 'generating',
    completedSteps: ['validating', 'testing', 'complete'],
  },
  {
    id: 'validate',
    label: 'A11y Validator',
    description: 'Enforcing WCAG 2.1 AA rules',
    icon: <ShieldCheck className="w-4 h-4" />,
    activeStep: 'validating',
    completedSteps: ['testing', 'complete'],
  },
  {
    id: 'test',
    label: 'Test Generator',
    description: 'Creating RTL + Playwright tests',
    icon: <TestTube className="w-4 h-4" />,
    activeStep: 'testing',
    completedSteps: ['complete'],
  },
  {
    id: 'preview',
    label: 'Live Preview',
    description: 'Rendering in Sandpack sandbox',
    icon: <Eye className="w-4 h-4" />,
    activeStep: 'complete',
    completedSteps: [],
  },
];

export default function PipelineStatus({ currentStep, errorMessage }: PipelineStatusProps) {
  if (currentStep === 'idle') return null;

  const getStepState = (step: Step) => {
    if (currentStep === 'error') return 'error';
    if (step.completedSteps.includes(currentStep)) return 'complete';
    if (step.activeStep === currentStep) return 'active';
    return 'pending';
  };

  return (
    <div
      className="w-full rounded-xl border border-gray-700/50 bg-gray-900/60 backdrop-blur-sm p-6"
      role="status"
      aria-label="Component generation pipeline status"
      aria-live="polite"
    >
      <div className="flex items-center gap-2 mb-6">
        <Zap className="w-4 h-4 text-blue-400" />
        <span className="text-xs font-semibold text-blue-400 uppercase tracking-wider">
          Generation Pipeline
        </span>
      </div>

      <div className="flex items-start gap-0 relative">
        {/* Connector line */}
        <div
          className="absolute top-5 left-5 h-px bg-gray-700"
          style={{ right: '1.25rem' }}
          aria-hidden="true"
        />

        {STEPS.map((step, index) => {
          const state = getStepState(step);

          return (
            <div
              key={step.id}
              className="flex-1 flex flex-col items-center gap-2 relative"
            >
              {/* Step circle */}
              <div
                className={`
                  relative z-10 w-10 h-10 rounded-full flex items-center justify-center
                  transition-all duration-500
                  ${state === 'complete'
                    ? 'bg-green-500/20 border-2 border-green-500 text-green-400'
                    : state === 'active'
                    ? 'bg-blue-500/20 border-2 border-blue-500 text-blue-400 ring-4 ring-blue-500/20'
                    : state === 'error'
                    ? 'bg-red-500/20 border-2 border-red-500 text-red-400'
                    : 'bg-gray-800 border-2 border-gray-600 text-gray-500'
                  }
                `}
                aria-label={`${step.label}: ${state}`}
              >
                {state === 'complete' ? (
                  <CheckCircle className="w-4 h-4" />
                ) : state === 'active' ? (
                  <Loader2 className="w-4 h-4 animate-spin" />
                ) : state === 'error' && index === STEPS.findIndex(s => s.activeStep === currentStep) ? (
                  <AlertCircle className="w-4 h-4" />
                ) : (
                  step.icon
                )}
              </div>

              {/* Step label */}
              <div className="text-center px-1">
                <p className={`text-xs font-semibold ${
                  state === 'complete' ? 'text-green-400' :
                  state === 'active' ? 'text-blue-400' :
                  state === 'error' ? 'text-red-400' :
                  'text-gray-500'
                }`}>
                  {step.label}
                </p>
                {state === 'active' && (
                  <p className="text-[10px] text-gray-400 mt-0.5 leading-tight max-w-[80px]">
                    {step.description}
                  </p>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* Error message */}
      {currentStep === 'error' && errorMessage && (
        <div
          className="mt-4 p-3 rounded-lg bg-red-950/50 border border-red-500/30 flex items-start gap-2"
          role="alert"
        >
          <AlertCircle className="w-4 h-4 text-red-400 flex-shrink-0 mt-0.5" />
          <p className="text-sm text-red-300">{errorMessage}</p>
        </div>
      )}
    </div>
  );
}

'use client';

import React, { useState, useEffect, useCallback } from 'react';
import {
  Sparkles, Eye, Code, FileCode, Layers, Clock, FolderKanban,
} from 'lucide-react';
import { type UIIntent, type A11yReport } from '@/lib/validation/schemas';
import type { ProjectVersion } from '@/lib/projects/projectStore';
import VersionTimeline from './VersionTimeline';
import dynamic from 'next/dynamic';

const SandpackPreview = dynamic(() => import('./SandpackPreview'), {
  ssr: false,
  loading: () => (
    <div className="rounded-xl border border-gray-700/50 bg-gray-900/60 h-48 flex items-center justify-center">
      <span className="text-gray-500 text-sm">Loading live preview...</span>
    </div>
  ),
});

// ─── Types ────────────────────────────────────────────────────────────────────

interface ProjectIteration {
  id: string;
  timestamp: string;
  code: string | Record<string, string>;
  intent: UIIntent;
  a11yReport: A11yReport;
  componentName: string;
}

interface ProjectWorkspaceProps {
  initialProject: ProjectIteration;
  onRefine: (prompt: string) => Promise<void>;
  isRefining: boolean;
  projectId?: string | null;
}

// ─── Quick Refinement Chips ───────────────────────────────────────────────────

const QUICK_REFINEMENTS = [
  'Make it mobile responsive',
  'Use a dark editorial aesthetic',
  'Add smooth micro-animations',
  'Improve accessibility',
  'Make colors more vibrant',
];

// ─── Component ────────────────────────────────────────────────────────────────

export default function ProjectWorkspace({
  initialProject,
  onRefine,
  isRefining,
  projectId,
}: ProjectWorkspaceProps) {
  const [versions, setVersions] = useState<ProjectVersion[]>([
    {
      version: 1,
      timestamp: initialProject.timestamp,
      code: initialProject.code,
      intent: initialProject.intent,
      a11yReport: initialProject.a11yReport,
      changeDescription: 'Initial generation',
    },
  ]);
  const [currentVersion, setCurrentVersion] = useState(1);
  const [viewMode, setViewMode] = useState<'preview' | 'code'>('preview');
  const [refinementPrompt, setRefinementPrompt] = useState('');
  const [isRollingBack, setIsRollingBack] = useState(false);

  const activeVersion = versions.find(v => v.version === currentVersion) ?? versions[versions.length - 1];

  // Sync new project changes from parent
  useEffect(() => {
    if (initialProject.id !== (versions[0]?.intent?.componentName ?? '')) {
      setVersions([{
        version: 1,
        timestamp: initialProject.timestamp,
        code: initialProject.code,
        intent: initialProject.intent,
        a11yReport: initialProject.a11yReport,
        changeDescription: 'Initial generation',
      }]);
      setCurrentVersion(1);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [initialProject.id]);

  // When parent generates a new output (refinement), append as new version
  useEffect(() => {
    // Only track new outputs after the initial load
    if (!isRefining) {
      const exists = versions.some(
        v => v.timestamp === initialProject.timestamp && v.code === initialProject.code,
      );
      if (!exists && versions.length > 0) {
        const newVer: ProjectVersion = {
          version: versions.length + 1,
          timestamp: initialProject.timestamp,
          code: initialProject.code,
          intent: initialProject.intent,
          a11yReport: initialProject.a11yReport,
          changeDescription: initialProject.intent.description || 'Refined version',
        };
        setVersions(prev => [...prev, newVer]);
        setCurrentVersion(newVer.version);
      }
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [initialProject.timestamp, isRefining]);

  const handleRollback = useCallback(async (version: number) => {
    if (!projectId) {
      // Local-only rollback
      setCurrentVersion(version);
      return;
    }
    setIsRollingBack(true);
    try {
      const res = await fetch(`/api/projects/${projectId}/rollback`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ version }),
      });
      const data = await res.json();
      if (data.success && data.project) {
        const proj = data.project;
        setVersions(proj.versions);
        setCurrentVersion(proj.currentVersion);
      }
    } catch { /* ignore */ } finally {
      setIsRollingBack(false);
    }
  }, [projectId]);

  const handleQuickRefine = (suggestion: string) => {
    setRefinementPrompt(suggestion);
  };

  const handleRefineSubmit = async () => {
    if (!refinementPrompt.trim() || isRefining) return;
    const prompt = refinementPrompt.trim();
    setRefinementPrompt('');
    await onRefine(prompt);
  };

  return (
    <div className="flex flex-col bg-gray-950/20 rounded-2xl border border-gray-700/30 overflow-hidden backdrop-blur-md">
      {/* Workspace Header */}
      <header className="flex items-center justify-between px-6 py-4 border-b border-gray-700/30 bg-gray-900/60 flex-wrap gap-3">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-blue-500/10 rounded-lg border border-blue-500/20">
            <Layers className="w-5 h-5 text-blue-400" />
          </div>
          <div>
            <h2 className="text-lg font-bold text-white leading-tight">
              {activeVersion.intent.componentName}
            </h2>
            <p className="text-xs text-gray-400 flex items-center gap-1.5 mt-0.5">
              <Clock className="w-3 h-3" />
              v{currentVersion} of {versions.length}
              {' · '}
              {new Date(activeVersion.timestamp).toLocaleTimeString()}
            </p>
          </div>
        </div>

        {/* View mode toggle */}
        <div className="flex items-center gap-2 bg-gray-950/40 p-1 rounded-xl border border-gray-800">
          <button
            onClick={() => setViewMode('preview')}
            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${
              viewMode === 'preview'
                ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20'
                : 'text-gray-400 hover:text-white hover:bg-gray-800'
            }`}
          >
            <Eye className="w-3.5 h-3.5" />
            Preview
          </button>
          <button
            onClick={() => setViewMode('code')}
            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${
              viewMode === 'code'
                ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20'
                : 'text-gray-400 hover:text-white hover:bg-gray-800'
            }`}
          >
            <Code className="w-3.5 h-3.5" />
            Code
          </button>
        </div>
      </header>

      {/* Body */}
      <div className="flex flex-1 overflow-hidden min-h-0" style={{ minHeight: '500px' }}>
        {/* Version Timeline Sidebar */}
        <VersionTimeline
          versions={versions}
          currentVersion={currentVersion}
          onSelectVersion={(ver) => setCurrentVersion(ver.version)}
          onRollback={handleRollback}
          isRollingBack={isRollingBack}
        />

        {/* Main Content */}
        <main className="flex-1 flex flex-col relative bg-gray-950/40 overflow-hidden">
          {/* Preview / Code Area */}
          <div className="flex-1 overflow-auto p-6">
            {viewMode === 'preview' ? (
              <div className="h-full min-h-[400px] rounded-2xl border border-gray-700/50 bg-white/5 overflow-hidden relative group">
                <div className="absolute top-4 left-4 z-10 opacity-0 group-hover:opacity-100 transition-opacity">
                  <div className="px-3 py-1 bg-gray-900/90 rounded-full border border-gray-700 text-[10px] text-gray-300 flex items-center gap-2">
                    <Eye className="w-3 h-3" /> Live Sandpack Runtime
                  </div>
                </div>
                <SandpackPreview
                  code={activeVersion.code as any}
                  componentName={activeVersion.intent.componentName}
                />
              </div>
            ) : (
              <div className="h-full min-h-[400px] rounded-2xl border border-gray-700/50 bg-gray-950 overflow-hidden font-mono text-xs">
                <div className="flex items-center gap-2 px-4 py-2 border-b border-gray-800 bg-gray-900/40">
                  <FileCode className="w-3 h-3 text-blue-400" />
                  <span className="text-gray-300">{activeVersion.intent.componentName}.tsx</span>
                  <span className="ml-auto text-[10px] text-gray-500">
                    {typeof activeVersion.code === 'string'
                      ? `${activeVersion.code.split('\n').length} lines`
                      : `${Object.keys(activeVersion.code).length} files`}
                  </span>
                </div>
                <pre className="p-6 text-gray-300 overflow-auto h-[calc(100%-40px)] leading-relaxed">
                  {typeof activeVersion.code === 'string'
                    ? activeVersion.code
                    : JSON.stringify(activeVersion.code, null, 2)}
                </pre>
              </div>
            )}
          </div>

          {/* Refinement Bar */}
          <div className="flex-shrink-0 p-5 border-t border-gray-700/30 bg-gray-900/40 backdrop-blur-xl">
            <div className="max-w-3xl mx-auto space-y-3">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2 text-xs text-gray-400">
                  <Sparkles className="w-3.5 h-3.5 text-blue-400" />
                  <span>Refine this project</span>
                </div>
                <span className="text-[10px] text-gray-500">
                  A11y: {activeVersion.a11yReport.score}/100
                </span>
              </div>

              {/* Refinement Input */}
              <div className="flex gap-2">
                <input
                  type="text"
                  value={refinementPrompt}
                  onChange={e => setRefinementPrompt(e.target.value)}
                  onKeyDown={e => e.key === 'Enter' && handleRefineSubmit()}
                  placeholder="Describe what to change… e.g. 'Make the sidebar dark with icons'"
                  disabled={isRefining}
                  className="flex-1 px-4 py-2.5 bg-gray-800/60 border border-gray-700/50 rounded-xl text-sm text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500/50 disabled:opacity-50 transition"
                />
                <button
                  onClick={handleRefineSubmit}
                  disabled={!refinementPrompt.trim() || isRefining}
                  className="px-5 py-2.5 rounded-xl bg-blue-600 hover:bg-blue-500 text-white text-sm font-semibold disabled:opacity-40 disabled:cursor-not-allowed transition-all shadow-lg shadow-blue-600/20"
                >
                  {isRefining ? 'Refining…' : 'Refine'}
                </button>
              </div>

              {/* Quick suggestions */}
              <div className="flex flex-wrap gap-2">
                {QUICK_REFINEMENTS.map(sug => (
                  <button
                    key={sug}
                    onClick={() => handleQuickRefine(sug)}
                    className="px-3 py-1 rounded-full border border-gray-700/50 bg-gray-800/30 text-[11px] text-gray-400 hover:bg-gray-700/60 hover:text-gray-200 transition-colors"
                  >
                    {sug}
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* Refining Overlay */}
          {isRefining && (
            <div className="absolute inset-0 z-50 bg-gray-950/70 backdrop-blur-sm flex items-center justify-center">
              <div className="flex flex-col items-center gap-4 text-center">
                <div className="relative">
                  <div className="w-16 h-16 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin" />
                  <Sparkles className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-6 h-6 text-blue-400 animate-pulse" />
                </div>
                <div>
                  <h3 className="text-lg font-bold text-white tracking-tight">Evolving Design</h3>
                  <p className="text-sm text-gray-400">Applying intelligent patches...</p>
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
}

'use client';

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Send, Loader2, ChevronRight, Mic, X, Plus, Command, Clock, Sparkles } from 'lucide-react';
import IntentBadge from './IntentBadge';
import type { IntentClassification } from '@/lib/validation/schemas';

export type GenerationMode = 'component' | 'app' | 'webgl';

interface PromptInputProps {
  onSubmit: (prompt: string, mode: GenerationMode) => void;
  isLoading: boolean;
  onIntentDetected?: (classification: IntentClassification) => void;
  hasActiveProject?: boolean;
}

export default function PromptInput({ onSubmit, isLoading, onIntentDetected, hasActiveProject }: PromptInputProps) {
  const [prompt, setPrompt] = useState('');
  const [mode, setMode] = useState<GenerationMode>('component');
  const [isFocused, setIsFocused] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isProcessingImage, setIsProcessingImage] = useState(false);
  const [history, setHistory] = useState<{ id: string, componentName: string, promptSnippet: string }[]>([]);
  const [liveIntent, setLiveIntent] = useState<IntentClassification | null>(null);
  const [isClassifying, setIsClassifying] = useState(false);
  const classifyTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    fetch('/api/history')
      .then((res) => res.json())
      .then((data) => {
        if (data.history && Array.isArray(data.history)) {
          setHistory(data.history);
        }
      })
      .catch((err) => console.error('Failed to load history', err));
  }, []);

  useEffect(() => {
    if (typeof window !== 'undefined') {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      if (SpeechRecognition) {
        try {
          recognitionRef.current = new SpeechRecognition();
          recognitionRef.current.continuous = true;
          recognitionRef.current.interimResults = true;

          recognitionRef.current.onresult = (event: any) => {
            let finalTranscript = '';
            for (let i = event.resultIndex; i < event.results.length; ++i) {
              if (event.results[i].isFinal) {
                finalTranscript += event.results[i][0].transcript + ' ';
              }
            }
            if (finalTranscript) {
              setPrompt((prev) => (prev ? prev.trim() + ' ' : '') + finalTranscript.trim() + ' ');
            }
          };

          recognitionRef.current.onerror = (event: any) => {
            console.error("Speech recognition error:", event.error);
            setIsRecording(false);
          };

          recognitionRef.current.onend = () => {
            setIsRecording(false);
          };
        } catch (e) {
          console.warn("Speech recognition initialization failed", e);
        }
      }
    }
  }, []);

  const toggleRecording = () => {
    if (!recognitionRef.current) {
      alert('Voice input is not supported in this browser. Please use Chrome, Edge, or Safari.');
      return;
    }

    if (isRecording) {
      recognitionRef.current.stop();
      setIsRecording(false);
    } else {
      try {
        recognitionRef.current.start();
        setIsRecording(true);
      } catch (e) {
        console.error(e);
        setIsRecording(false);
      }
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const file = e.target.files[0];

      if (!file.type.startsWith('image/')) {
        alert('Please select an image file to extract text from.');
        return;
      }

      setIsProcessingImage(true);

      try {
        const formData = new FormData();
        formData.append('image', file);

        const response = await fetch('/api/image-to-text', {
          method: 'POST',
          body: formData,
        });

        if (!response.ok) {
          const data = await response.json();
          throw new Error(data.error || 'Failed to analyze image');
        }

        const data = await response.json();

        if (data.caption) {
           setPrompt((prev) => prev + (prev.endsWith(' ') ? '' : ' ') + `[Image Context: ${data.caption}] `);
        }
      } catch (error: any) {
        alert(error.message || 'There was an error analyzing the image.');
      } finally {
        setIsProcessingImage(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    }
  };

  // Debounced live intent classification
  const scheduleClassify = useCallback((text: string) => {
    if (classifyTimerRef.current) clearTimeout(classifyTimerRef.current);
    if (text.trim().length < 10) { setLiveIntent(null); return; }
    classifyTimerRef.current = setTimeout(async () => {
      setIsClassifying(true);
      try {
        const res = await fetch('/api/classify', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ prompt: text, hasActiveProject: hasActiveProject ?? false }),
        });
        const data = await res.json();
        if (data.success && data.classification) {
          setLiveIntent(data.classification);
          onIntentDetected?.(data.classification);
        }
      } catch { /* ignore */ } finally {
        setIsClassifying(false);
      }
    }, 600);
  }, [hasActiveProject, onIntentDetected]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (prompt.trim() && !isLoading) {
      onSubmit(prompt.trim(), mode);
      setPrompt('');
      setIsRecording(false);
      setLiveIntent(null);
    }
  };

  const charCount = prompt.length;
  const maxChars = 10000;
  const isOverLimit = charCount > maxChars;

  const placeholder = mode === 'app'
    ? 'Describe a full app in one line, e.g. "Build an Instagram-like social media app" or "Create a Spotify music player"'
    : 'Describe a UI component, e.g. "A login form with email and password" or paste a design prompt…';

  return (
    <section aria-labelledby="prompt-heading">
      <div className="mb-4">
        <div className="flex items-center gap-2 mb-3">
          <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-blue-500 to-violet-600 flex items-center justify-center shadow-lg shadow-blue-500/20">
            <Command className="w-4 h-4 text-white" />
          </div>
          <div>
            <h2 id="prompt-heading" className="text-lg font-semibold text-white">
              Describe Your UI
            </h2>
            <p className="text-xs text-gray-400">
              Natural language → accessible React {mode === 'app' ? 'application' : 'component'}
            </p>
          </div>
        </div>

        {/* ── Mode Toggle ─────────────────────────────────────────── */}
        <div
          role="group"
          aria-label="Generation mode"
          className="inline-flex items-center gap-1 p-1 rounded-xl bg-gray-800/60 border border-gray-700/40 mb-3"
        >
          <button
            type="button"
            onClick={() => setMode('component')}
            aria-pressed={mode === 'component'}
            disabled={isLoading}
            className={`
              flex items-center gap-2 px-4 py-1.5 rounded-lg text-sm font-medium transition-all duration-200
              focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-1 focus:ring-offset-gray-800
              disabled:opacity-50 disabled:cursor-not-allowed
              ${mode === 'component'
                ? 'bg-gradient-to-r from-blue-600 to-blue-500 text-white shadow-md shadow-blue-500/25'
                : 'text-gray-400 hover:text-white'
              }
            `}
          >
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="w-3.5 h-3.5" aria-hidden="true">
              <rect x="3" y="3" width="7" height="7" rx="1" />
              <rect x="14" y="3" width="7" height="7" rx="1" />
              <rect x="3" y="14" width="7" height="7" rx="1" />
              <rect x="14" y="14" width="7" height="7" rx="1" />
            </svg>
            Component
          </button>
          <button
            type="button"
            onClick={() => setMode('app')}
            aria-pressed={mode === 'app'}
            disabled={isLoading}
            className={`
              flex items-center gap-2 px-4 py-1.5 rounded-lg text-sm font-medium transition-all duration-200
              focus:outline-none focus:ring-2 focus:ring-violet-500 focus:ring-offset-1 focus:ring-offset-gray-800
              disabled:opacity-50 disabled:cursor-not-allowed
              ${mode === 'app'
                ? 'bg-gradient-to-r from-violet-600 to-purple-500 text-white shadow-md shadow-violet-500/25'
                : 'text-gray-400 hover:text-white'
              }
            `}
          >
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="w-3.5 h-3.5" aria-hidden="true">
              <path d="M12 2L2 7l10 5 10-5-10-5z" />
              <path d="M2 17l10 5 10-5" />
              <path d="M2 12l10 5 10-5" />
            </svg>
            Full App
          </button>
          <button
            type="button"
            onClick={() => setMode('webgl')}
            aria-pressed={mode === 'webgl'}
            disabled={isLoading}
            className={`
              flex items-center gap-2 px-4 py-1.5 rounded-lg text-sm font-medium transition-all duration-200
              focus:outline-none focus:ring-2 focus:ring-cyan-500 focus:ring-offset-1 focus:ring-offset-gray-800
              disabled:opacity-50 disabled:cursor-not-allowed
              ${mode === 'webgl'
                ? 'bg-gradient-to-r from-cyan-600 to-blue-500 text-white shadow-md shadow-cyan-500/25'
                : 'text-gray-400 hover:text-white'
              }
            `}
          >
            <span role="img" aria-hidden="true" className="text-[14px] leading-none">🧊</span>
            3D WebGL
            <span className="text-[10px] px-1.5 py-0.5 rounded-full bg-cyan-400/20 text-cyan-300 font-semibold">NEW</span>
          </button>
        </div>

        {/* Hints */}
        {mode === 'app' && (
          <div className="flex items-start gap-2 px-3 py-2 rounded-lg bg-violet-500/10 border border-violet-500/20 mb-3">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className="w-4 h-4 text-violet-400 flex-shrink-0 mt-0.5" aria-hidden="true">
              <circle cx="12" cy="12" r="10" />
              <line x1="12" y1="8" x2="12" y2="12" />
              <line x1="12" y1="16" x2="12.01" y2="16" />
            </svg>
            <p className="text-xs text-violet-300 leading-relaxed">
              <span className="font-semibold text-violet-200">Full App Mode:</span> Generates a complete multi-screen application with navigation and mock data. Try: <span className="italic">"Build an Instagram-like app"</span>.
            </p>
          </div>
        )}
        {mode === 'webgl' && (
          <div className="flex items-start gap-2 px-3 py-2 rounded-lg bg-cyan-500/10 border border-cyan-500/20 mb-3">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className="w-4 h-4 text-cyan-400 flex-shrink-0 mt-0.5" aria-hidden="true">
              <polygon points="12 2 2 7 12 12 22 7 12 2" />
              <polyline points="2 17 12 22 22 17" />
              <polyline points="2 12 12 17 22 12" />
            </svg>
            <p className="text-xs text-cyan-300 leading-relaxed">
              <span className="font-semibold text-cyan-200">3D WebGL Mode:</span> Generates interactive 3D scenes using React Three Fiber. Try: <span className="italic">"Build a 3D portfolio landing page with floating rotating cubes"</span>.
            </p>
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} aria-label="UI generation form" className="relative group">
        <div className={`
          relative flex flex-col w-full transition-all duration-300
          bg-[#212121] backdrop-blur-md border border-[#303030] 
          ${isFocused ? 'ring-1 ring-white/10 shadow-2xl' : 'hover:border-[#404040] shadow-xl'}
          ${mode === 'app' ? 'ring-1 ring-violet-500/20' : ''}
          ${mode === 'webgl' ? 'ring-1 ring-cyan-500/20' : ''}
          rounded-2xl overflow-hidden
        `}>

          {/* Active Recording State */}
          {isRecording && (
            <div className="flex flex-wrap gap-2 px-3 pt-3 pb-1 border-b border-[#303030]/50" role="region" aria-label="Recording active">
              <div className="flex items-center gap-2 bg-red-500/10 border border-red-500/20 rounded-xl py-1 px-3 text-xs text-red-400">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-red-500"></span>
                </span>
                Listening... Speak clearly.
                <button type="button" onClick={toggleRecording} className="ml-1 text-red-500 hover:text-white transition-colors" aria-label="Stop recording">
                  <X className="w-3 h-3" />
                </button>
              </div>
            </div>
          )}

          {/* Expanding Text Area */}
          <div className="relative p-3 pb-0">
            <textarea
              id="component-prompt"
              name="component-prompt"
              rows={prompt.split('\n').length > 5 ? Math.min(prompt.split('\n').length, 15) : mode === 'app' ? 4 : 5}
              className="
                w-full resize-y bg-transparent text-zinc-100
                placeholder-zinc-500 text-sm sm:text-base leading-relaxed
                outline-none focus:outline-none min-h-[100px] max-h-[600px] overflow-y-auto
              "
              placeholder={placeholder}
              value={prompt}
              onChange={(e) => { setPrompt(e.target.value); scheduleClassify(e.target.value); }}
              onFocus={() => setIsFocused(true)}
              onBlur={() => setIsFocused(false)}
              disabled={isLoading}
              maxLength={maxChars + 100}
              aria-label={mode === 'app' ? 'App description' : 'Component description'}
              aria-required="true"
            />

            {/* Live intent hint */}
            {(liveIntent || isClassifying) && (
              <div className="flex items-center gap-2 px-1 py-1.5">
                {isClassifying ? (
                  <span className="flex items-center gap-1.5 text-[11px] text-gray-500">
                    <Sparkles className="w-3 h-3 animate-pulse text-blue-400" />
                    Analyzing intent…
                  </span>
                ) : liveIntent ? (
                  <>
                    <span className="text-[11px] text-gray-500">Detected:</span>
                    <IntentBadge intentType={liveIntent.intentType} confidence={liveIntent.confidence} size="sm" />
                    {!liveIntent.shouldGenerateCode && (
                      <span className="text-[11px] text-amber-400/80 italic">Will show planning panel first</span>
                    )}
                  </>
                ) : null}
              </div>
            )}
          </div>

          {/* Bottom Action Bar */}
          <div className="flex items-center justify-between px-3 py-2 bg-[#212121]/50 border-t border-[#303030]/30">
            {/* Left Actions */}
            <div className="flex items-center gap-2">
              <input
                type="file"
                ref={fileInputRef}
                onChange={handleFileUpload}
                className="hidden"
                accept="image/jpeg,image/png,image/gif,image/webp"
              />
              <button 
                type="button" 
                onClick={() => fileInputRef.current?.click()}
                disabled={isProcessingImage}
                aria-label="Attach image for AI analysis"
                className="p-1.5 text-zinc-400 hover:text-white hover:bg-white/10 rounded-md transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:opacity-50 flex items-center gap-1.5 text-xs font-medium"
              >
                {isProcessingImage ? <Loader2 className="w-4 h-4 stroke-[2] animate-spin text-blue-400" /> : <Plus className="w-4 h-4 stroke-[2]" />}
                <span className="hidden sm:inline">Attach</span>
              </button>
            </div>

            {/* Right Actions & Submit */}
            <div className="flex items-center gap-2">
              <span className={`text-xs mr-2 transition-opacity duration-300 ${charCount > maxChars ? 'text-red-400 opacity-100' : 'text-zinc-500 opacity-0 group-hover:opacity-100'}`}>
                {charCount}/{maxChars}
              </span>

              {isLoading && (
                <div className="w-2 h-2 rounded-full bg-emerald-500 mr-2 animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.6)]"></div>
              )}

              <button
                type="button"
                onClick={toggleRecording}
                aria-label={isRecording ? 'Stop recording' : 'Start voice input'}
                className={`p-2 rounded-lg transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 ${isRecording ? 'bg-red-500/20 text-red-500' : 'text-zinc-400 hover:text-white hover:bg-white/10'}`}
              >
                <Mic className="w-4 h-4 stroke-[2]" />
              </button>

              <button
                type="submit"
                disabled={!prompt.trim() || isLoading || isOverLimit || isProcessingImage}
                aria-label={isLoading ? 'Generating, please wait' : mode === 'app' ? 'Generate full app' : 'Generate component'}
                className={`
                  flex items-center justify-center px-4 py-1.5 rounded-lg
                  transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-[#212121]
                  ${mode === 'app' ? 'focus:ring-violet-500' : mode === 'webgl' ? 'focus:ring-cyan-500' : 'focus:ring-white'}
                  ${isLoading || !prompt.trim() 
                    ? 'bg-zinc-700 text-zinc-400 cursor-not-allowed opacity-50' 
                    : mode === 'app'
                      ? 'bg-gradient-to-r from-violet-600 to-purple-500 text-white hover:from-violet-500 hover:to-purple-400 shadow-md shadow-violet-500/25 font-medium text-sm'
                      : mode === 'webgl'
                        ? 'bg-gradient-to-r from-cyan-600 to-blue-500 text-white hover:from-cyan-500 hover:to-blue-400 shadow-md shadow-cyan-500/25 font-medium text-sm'
                        : 'bg-white text-black hover:bg-gray-200 shadow-md font-medium text-sm'
                  }
                `}
              >
                {isLoading ? (
                  <Loader2 className="w-4 h-4 animate-spin" aria-hidden="true" />
                ) : (
                  <>
                    <span className="mr-1.5">{mode === 'app' ? 'Build App' : mode === 'webgl' ? 'Build 3D' : 'Generate'}</span>
                    <Send className="w-3.5 h-3.5 block" aria-hidden="true" />
                  </>
                )}
              </button>
            </div>
          </div>
        </div>

        <p id="prompt-hint" className="sr-only">
          {mode === 'app'
            ? 'Describe a full application to generate a complete multi-screen React app with navigation and mock data.'
            : 'Enter a description of the UI component you want to build, then click Generate.'}
        </p>
      </form>

      {/* Generation History */}
      <div className="mt-4" role="group" aria-label="Prompt history">
        <p className="flex items-center gap-1.5 text-xs text-gray-400 mb-2 font-medium">
          <Clock className="w-3 h-3 block" />
          Your Generation History
        </p>
        <div className="flex flex-wrap gap-2">
          {history.length > 0 ? (
            history.map((item) => (
              <button
                key={item.id}
                type="button"
                onClick={() => setPrompt(item.promptSnippet)}
                disabled={isLoading}
                aria-label={`Reuse history: ${item.componentName}`}
                className="
                  flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs
                  border border-blue-900/40 text-blue-400 bg-blue-500/10
                  hover:border-blue-500/60 hover:text-blue-300 hover:bg-blue-500/20
                  disabled:opacity-50 disabled:cursor-not-allowed
                  transition-all duration-150
                  focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-1 focus:ring-offset-gray-950
                "
              >
                <ChevronRight className="w-3 h-3 block" aria-hidden="true" />
                <span className="font-semibold">{item.componentName}:</span> 
                <span className="truncate max-w-[200px] sm:max-w-[400px]">{item.promptSnippet}</span>
              </button>
            ))
          ) : (
            <div className="text-xs text-zinc-500 italic flex items-center gap-2 bg-black/20 px-3 py-1.5 rounded-full border border-white/5">
              Nothing here yet. Build your first component or app!
            </div>
          )}
        </div>
      </div>
    </section>
  );
}

