                          {project.name}
                        </span>
                        <ChevronRight className={`w-3 h-3 flex-shrink-0 transition-transform ${isActive ? 'text-blue-400 opacity-100 translate-x-0' : 'text-gray-600 opacity-0 -translate-x-2 group-hover:opacity-100 group-hover:translate-x-0'}`} />
                      </div>
                      <p className="text-[11px] text-gray-500 flex items-center gap-1.5 mt-1.5">
                        <Clock className="w-3 h-3 text-gray-600" />
                        <span className="truncate">{new Date(project.updatedAt).toLocaleDateString(undefined, { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' })}</span>
                      </p>
                    </div>
                  </div>
                </button>
              );
            })
          )}
        </div>

        {/* Footer / User Settings placeholder */}
        <div className="p-4 mt-auto border-t border-gray-800/60 bg-gray-950/80 flex items-center justify-between shrink-0">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-gray-700 to-gray-600 flex items-center justify-center flex-shrink-0">
              <span className="text-xs font-bold text-white">US</span>
            </div>
            <div className="min-w-0 pr-2">
              <p className="text-xs font-semibold text-gray-200 truncate">Developer Flow</p>
              <p className="text-[10px] text-gray-500 truncate">Pro Workspace</p>
            </div>
          </div>
          <button className="p-2 text-gray-500 hover:text-white hover:bg-gray-800 rounded-lg transition-colors" aria-label="Settings">
            <Settings className="w-4 h-4" />
          </button>
        </div>
      </aside>
    </>
  );
