import OpenAI from 'openai';
import { type UIIntent } from '../validation/schemas';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

export interface FileManifestItem {
  filename: string;
  description: string;
}

function mapModel(req: string): string {
  if (req.includes('nano') || req.includes('mini')) return 'gpt-4o-mini';
  if (req === 'gpt-4.1') return 'gpt-4-turbo';
  if (req.includes('5.4')) return 'gpt-4o';
  return req || 'gpt-4o';
}

export async function generateAppManifest(
  intent: UIIntent,
  model: string,
  isMultiSlide: boolean = false
): Promise<FileManifestItem[]> {
  let prompt = "You are an elite React UI Architect. The user wants to build a massive application.\n" +
"Break this application down into a modular React architecture file manifest.\n" +
"You must return a valid JSON array of objects, where each object has \"filename\" and \"description\".\n" +
"The entry point MUST be named \"App.tsx\".\n" +
"Do NOT include package.json or index.html. Only React components.\n" +
"Include at least 4-6 files for a full application.\n\n" +
"USER INTENT:\n" +
JSON.stringify(intent, null, 2);

  if (isMultiSlide) {
    prompt += "\n\nCRITICAL MULTI-SLIDE ARCHITECTURE REQUIREMENT: The user requested a MULTI-SLIDE / PAGINATED experience. Ensure your manifest implies a router or slide orchestrator component (usually App.tsx) that manages navigation between distinct feature screens/views.";
  }

  const response = await openai.chat.completions.create({
    model: mapModel(model),
    messages: [{ role: 'user', content: prompt }],
    temperature: 0.3,
    response_format: { type: 'json_object' }, 
  });

  const raw = response.choices[0]?.message?.content || '[]';

  try {
    const parsed = JSON.parse(raw);
    if (Array.isArray(parsed)) return parsed;
    if (parsed.files && Array.isArray(parsed.files)) return parsed.files;
    if (parsed.manifest && Array.isArray(parsed.manifest)) return parsed.manifest;
    return [];
  } catch(e) {
    return [{ filename: 'App.tsx', description: 'Main application entry point' }];
  }
}

export async function generateFileChunk(
  intent: UIIntent,
  manifest: FileManifestItem[],
  targetFile: string,
  model: string,
  maxTokens: number,
  isMultiSlide: boolean = false
): Promise<string> {
  const fileDef = manifest.find((f) => f.filename === targetFile);

  let prompt = "You are an elite React/TypeScript engineer building a massive application.\n" +
"We are chunking the generation. You are currently writing the file: \"" + targetFile + "\".\n\n" +
"FILE DESCRIPTION: " + (fileDef ? fileDef.description : 'Component for the app') + "\n\n" +
"APP MANIFEST (For Context / Imports):\n" +
JSON.stringify(manifest, null, 2) + "\n\n" +
"USER INTENT:\n" +
JSON.stringify(intent, null, 2) + "\n\n" +
"REQUIREMENTS:\n" +
"1. Write ONLY the raw TSX code for \"" + targetFile + "\". No markdown fences, no explanations.\n" +
"2. Use Tailwind CSS exclusively for styling.\n" +
"3. Import other components from \"./[filename]\" relative paths. Use DEFAULT IMPORTS: \`import ComponentName from './ComponentName';\`\n" +
"4. Export default the main component of this file: \`export default function ComponentName() { ... }\`.\n" +
"5. If it is App.tsx, orchestrate the other components.\n" +
"6. Write dense, production-ready code.\n" +
"7. CRITICAL: Use \`lucide-react\` EXCLUSIVELY for icons. Import them individually using destructuring: \`import { ... } from 'lucide-react';\`\n" +
"8. NEVER import from \"./utils/\", \"./hooks/\", or other non-existent paths. All custom logic and hooks must be self-contained within this file or imported ONLY from components/files listed in the APP MANIFEST above.\n\n";

  if (isMultiSlide) {
    prompt += "CRITICAL MULTI-SLIDE ARCHITECTURE REQUIREMENT:\nThe app must function as a multi-slide or paginated experience. When generating App.tsx or view components, include robust navigation state (Next/Prev buttons, dots). For 3D WebGL scenes, alter the react-three-fiber camera or mesh positions over these slide states.\n\n";
  }

  prompt += "RETURN ONLY THE RAW CODE.";

  const response = await openai.chat.completions.create({
    model: mapModel(model),
    messages: [{ role: 'user', content: prompt }],
    temperature: 0.5,
    max_tokens: maxTokens || 4000,
  });

  let rawContent = response.choices[0]?.message?.content || '';

  const match = rawContent.match(/```(?:tsx?|jsx?|typescript|javascript)?\s*([\s\S]*?)(?:```|$)/i);
  if (match && match[1]) {
    rawContent = match[1].trim();
  } else {
    rawContent = rawContent.replace(/^```(?:tsx?|jsx?|typescript|javascript)?\n?/gim, '').replace(/```\s*$/gim, '').trim();
  }

  return rawContent;
}

import OpenAI from 'openai';
import {
  COMPONENT_GENERATOR_SYSTEM_PROMPT,
  APP_MODE_SYSTEM_PROMPT,
  WEBGL_MODE_SYSTEM_PROMPT,
  buildComponentGeneratorPrompt,
  buildAppModeGeneratorPrompt,
  buildWebglModeGeneratorPrompt,
  REFINEMENT_SYSTEM_PROMPT,
} from './prompts';
import { getRelevantExamples } from './memory';
import { findRelevantKnowledge, findAppTemplate, findWebglTemplate } from './knowledgeBase';
import { type UIIntent } from '../validation/schemas';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

export type GenerationMode = 'component' | 'app' | 'webgl';

export interface GenerationResult {
  success: boolean;
  code?: string;
  error?: string;
}

function mapModel(req: string): string {
  if (req.includes('nano') || req.includes('mini')) return 'gpt-4o-mini';
  if (req === 'gpt-4.1') return 'gpt-4-turbo';
  if (req.includes('5.4')) return 'gpt-4o';
  return req || 'gpt-4o';
}

function cleanGeneratedCode(raw: string): string {
  // Try to find a code block first, ignoring any conversational filler.
  const match = raw.match(/```(?:tsx?|jsx?|typescript|javascript)?\s*([\s\S]*?)(?:```|$)/i);
  if (match && match[1]) {
    return match[1].trim();
  }

  // Fallback: strip exact fences if no matching pair is found
  return raw
    .replace(/^```(?:tsx?|jsx?|typescript|javascript)?\n?/gim, '')
    .replace(/```\s*$/gim, '')
    .trim();
}

export async function generateComponent(
  intent: UIIntent,
  mode: GenerationMode = 'component',
  requestedModel: string = 'gpt-5.4-mini',
  maxTokens: number = 5000,
  isMultiSlide: boolean = false,
  refinementContext?: { code: string; manifest?: any }
): Promise<GenerationResult> {
  try {
    const searchText = intent.description + ' ' + intent.componentName;

    let knowledge: string | null;
    let systemPrompt: string;
    let userPrompt: string;

    if (intent.isRefinement && refinementContext) {
      systemPrompt = REFINEMENT_SYSTEM_PROMPT;
      userPrompt = `TARGET FILE CODE:\n${refinementContext.code}\n\n` +
                   `APP MANIFEST:\n${JSON.stringify(refinementContext.manifest || [], null, 2)}\n\n` +
                   `REFINEMENT INTENT:\n${JSON.stringify(intent, null, 2)}`;
    } else if (mode === 'webgl') {
      knowledge = findWebglTemplate(searchText) ?? findRelevantKnowledge(searchText);
      systemPrompt = WEBGL_MODE_SYSTEM_PROMPT;
      userPrompt = buildWebglModeGeneratorPrompt(intent, knowledge, isMultiSlide);
    } else if (mode === 'app') {
      knowledge = findAppTemplate(searchText) ?? findRelevantKnowledge(searchText);
      const memory = getRelevantExamples(intent);
      systemPrompt = APP_MODE_SYSTEM_PROMPT;
      userPrompt = buildAppModeGeneratorPrompt(intent, knowledge, memory, isMultiSlide);
    } else {
      knowledge = findRelevantKnowledge(searchText);
      const memory = getRelevantExamples(intent);
      systemPrompt = COMPONENT_GENERATOR_SYSTEM_PROMPT;
      userPrompt = buildComponentGeneratorPrompt(intent, knowledge, memory, isMultiSlide);
    }

    const response = await openai.chat.completions.create({
      model: mapModel(requestedModel),
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt },
      ],
      temperature: mode === 'app' || mode === 'webgl' ? 0.6 : 0.4,
      max_tokens: maxTokens || 5000,
    });
    const rawContent = response.choices[0]?.message?.content || '';

    if (!rawContent) {
      return { success: false, error: 'AI returned empty component code' };
    }

    const cleaned = cleanGeneratedCode(rawContent);

    // Basic sanity check
    if (!cleaned.includes('export') && !cleaned.includes('return')) {
      return {
        success: false,
        error: `Generated code does not appear to be a valid React component. AI Output start: "${cleaned.substring(0, 150)}..."`,
      };
    }

    return { success: true, code: cleaned };
  } catch (error) {
    const msg = error instanceof Error ? error.message : 'Unknown error';
    return { success: false, error: `OpenAI API error: ${msg}` };
  }
}

import type { UIIntent } from './validation/schemas';

interface GeneratedTests {
  rtl: string;
  playwright: string;
}

export function generateTests(intent: UIIntent, componentCode: string): GeneratedTests {
  const { componentName, fields, interactions, componentType } = intent;

  const rtl = generateRTLTests(componentName, fields, interactions, componentCode);
  const playwright = generatePlaywrightTests(componentName, fields, interactions, componentType);

  return { rtl, playwright };
}

function generateRTLTests(
  componentName: string,
  fields: UIIntent['fields'],
  interactions: UIIntent['interactions'],
  _code: string,
): string {
  const inputFields = fields.filter(f => ['text', 'email', 'password', 'textarea', 'number', 'tel'].includes(f.type));
  const buttonFields = fields.filter(f => f.type === 'button');
  const selectFields = fields.filter(f => f.type === 'select');
  const requiredFields = fields.filter(f => f.required);

  const interactionTests = interactions.map((interaction, i) => {
    if (interaction.trigger === 'submit') {
      return `
  it('handles form submission', async () => {
    const user = userEvent.setup();
    render(<${componentName} />);
    ${inputFields.slice(0, 2).map(f =>
      `await user.type(screen.getByLabelText('${f.label}'), 'test-value');`
    ).join('\n    ')}
    const submitButton = screen.getByRole('button', { name: /submit/i });
    await user.click(submitButton);
    // Verify feedback state
    expect(submitButton).not.toBeDisabled();
  });`;
    }
    if (interaction.trigger === 'click') {
      return `
  it('handles click interaction ${i + 1}', async () => {
    const user = userEvent.setup();
    render(<${componentName} />);
    // Test click interaction: ${interaction.action}
  });`;
    }
    return '';
  }).filter(Boolean);

  const validationTests = requiredFields.length > 0 ? `
  it('shows validation errors for required fields when empty', async () => {
    const user = userEvent.setup();
    render(<${componentName} />);
    const submitButton = screen.getByRole('button', { name: /submit/i });
    await user.click(submitButton);
    ${requiredFields.slice(0, 2).map(f =>
      `expect(screen.queryByText(/required/i) || screen.queryByRole('alert')).toBeInTheDocument();`
    ).join('\n    ')}
  });` : '';

  const inputInteractionTests = inputFields.slice(0, 3).map(f => `
  it('allows typing in ${f.label} field', async () => {
    const user = userEvent.setup();
    render(<${componentName} />);
    const input = screen.getByLabelText('${f.label}');
    await user.type(input, 'test input value');
    expect(input).toHaveValue('test input value');
  });`).join('');

  const selectInteractionTests = selectFields.slice(0, 2).map(f => `
  it('allows selecting option in ${f.label}', async () => {
    const user = userEvent.setup();
    render(<${componentName} />);
    const select = screen.getByLabelText('${f.label}');
    ${f.options.length > 0 ? `await user.selectOptions(select, '${f.options[0]}');
    expect(select).toHaveValue('${f.options[0]}');` : '// No options defined'}
  });`).join('');

  const buttonTests = buttonFields.slice(0, 2).map(f => `
  it('renders ${f.label} button', () => {
    render(<${componentName} />);
    expect(screen.getByRole('button', { name: /${f.label}/i })).toBeInTheDocument();
  });`).join('');

  return `/**
 * Auto-generated React Testing Library tests
 * Component: ${componentName}
 * Generated by AI-Powered Accessibility-First UI Engine
 */

import React from 'react';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import '@testing-library/jest-dom';
import ${componentName} from '../components/${componentName}';

describe('${componentName}', () => {
  // ─── Render Tests ──────────────────────────────────────────────────────────

  it('renders without crashing', () => {
    render(<${componentName} />);
    expect(document.body).toBeInTheDocument();
  });

${fields.slice(0, 4).map(f => `  it('renders ${f.label}', () => {
    render(<${componentName} />);
    expect(screen.getByText('${f.label}')).toBeInTheDocument();
  });`).join('\n\n')}

  // ─── Interaction Tests ─────────────────────────────────────────────────────
${inputInteractionTests}
${selectInteractionTests}
${buttonTests}
${interactionTests.join('')}
${validationTests}

  // ─── Accessibility Tests ───────────────────────────────────────────────────

  it('has no heading structure violations', () => {
    render(<${componentName} />);
    // All headings should be findable by role
    const headings = screen.queryAllByRole('heading');
    headings.forEach(heading => {
      expect(heading).toBeVisible();
    });
  });

  it('all interactive elements are keyboard accessible', () => {
    render(<${componentName} />);
    const buttons = screen.queryAllByRole('button');
    buttons.forEach(button => {
      expect(button).not.toHaveAttribute('tabindex', '-1');
    });
  });

  it('form inputs have associated labels', () => {
    render(<${componentName} />);
    const inputs = document.querySelectorAll('input, textarea, select');
    inputs.forEach(input => {
      const id = input.getAttribute('id');
      if (id) {
        const label = document.querySelector(\`label[for="\${id}"]\`);
        const ariaLabel = input.getAttribute('aria-label');
        expect(label || ariaLabel).toBeTruthy();
      }
    });
  });

  it('buttons have accessible names', () => {
    render(<${componentName} />);
    const buttons = screen.queryAllByRole('button');
    buttons.forEach(button => {
      expect(button).toHaveAccessibleName();
    });
  });
});
`;
}

function generatePlaywrightTests(
  componentName: string,
  fields: UIIntent['fields'],
  _interactions: UIIntent['interactions'],
  componentType: string,
): string {
  const inputFields = fields.filter(f => ['text', 'email', 'password', 'textarea'].includes(f.type));
  const requiredFields = fields.filter(f => f.required);

  const fillFormSteps = inputFields.slice(0, 3).map(f => {
    if (f.type === 'password') return `  await page.fill('input#${f.id}', 'SecurePass123!');`;
    if (f.type === 'email') return `  await page.fill('input#${f.id}', 'test@example.com');`;
    return `  await page.fill('input#${f.id}, textarea#${f.id}', 'Test Value');`;
  }).join('\n');

  return `/**
 * Auto-generated Playwright E2E tests
 * Component: ${componentName} (${componentType})
 * Generated by AI-Powered Accessibility-First UI Engine
 * 
 * Prerequisites: Run 'npx playwright install' before running these tests.
 * Update BASE_URL to point to your running application.
 */

import { test, expect } from '@playwright/test';

const BASE_URL = process.env.BASE_URL || 'http://localhost:3000';

test.describe('${componentName} E2E Tests', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto(BASE_URL);
  });

  // ─── Visual Tests ──────────────────────────────────────────────────────────

  test('page loads and component is visible', async ({ page }) => {
    await expect(page).toHaveTitle(/.+/);
    await expect(page.locator('body')).toBeVisible();
  });

  // ─── Keyboard Navigation Tests ─────────────────────────────────────────────

  test('all interactive elements are reachable by Tab', async ({ page }) => {
    await page.keyboard.press('Tab');
    const focusedElement = await page.evaluate(() => document.activeElement?.tagName);
    expect(['INPUT', 'BUTTON', 'SELECT', 'TEXTAREA', 'A']).toContain(focusedElement);
  });

  test('form can be submitted via keyboard', async ({ page }) => {
${fillFormSteps}
    await page.keyboard.press('Tab'); // Move to submit
    await page.keyboard.press('Enter');
    // Verify some feedback
    await expect(page.locator('body')).toBeVisible();
  });

  // ─── Accessibility Tests ───────────────────────────────────────────────────

  test('no accessibility violations (axe-core)', async ({ page }) => {
    // Install: npm install --save-dev @axe-core/playwright
    // import { checkA11y } from '@axe-core/playwright';
    // await checkA11y(page);
    // Placeholder: manual ARIA check
    const buttons = await page.locator('button').all();
    for (const button of buttons) {
      const name = await button.getAttribute('aria-label') || await button.textContent();
      expect(name?.trim()).toBeTruthy();
    }
  });

  test('focus indicators are visible', async ({ page }) => {
    await page.keyboard.press('Tab');
    const focusedEl = page.locator(':focus');
    await expect(focusedEl).toBeVisible();
  });

${requiredFields.length > 0 ? `  // ─── Validation Tests ──────────────────────────────────────────────────────

  test('shows errors when required fields are empty', async ({ page }) => {
    const submitButton = page.locator('button[type="submit"]').first();
    if (await submitButton.count() > 0) {
      await submitButton.click();
      // Verify error messages appear
      const errors = page.locator('[role="alert"], .text-red-500, [aria-live="polite"]');
      // Errors may or may not appear depending on implementation
      await expect(page.locator('body')).toBeVisible();
    }
  });` : ''}

  // ─── Mobile Viewport Tests ─────────────────────────────────────────────────

  test('component is responsive on mobile', async ({ page }) => {
    await page.setViewportSize({ width: 375, height: 812 });
    await expect(page.locator('body')).toBeVisible();
    // Ensure no horizontal scroll
    const scrollWidth = await page.evaluate(() => document.documentElement.scrollWidth);
    const clientWidth = await page.evaluate(() => document.documentElement.clientWidth);
    expect(scrollWidth).toBeLessThanOrEqual(clientWidth + 5); // 5px tolerance
  });
});
`;
}

import { z } from 'zod';

// ─── Intent Classification Schema ────────────────────────────────────────────

export const INTENT_TYPES = [
  'ui_generation',
  'ui_refinement',
  'product_requirement',
  'ideation',
  'debug_fix',
  'context_clarification',
] as const;

export type IntentType = typeof INTENT_TYPES[number];

export const IntentClassificationSchema = z.object({
  intentType: z.enum(INTENT_TYPES).catch('ui_generation'),
  confidence: z.number().min(0).max(1).catch(0.8),
  summary: z.string().catch(''),
  suggestedMode: z.enum(['component', 'app', 'webgl']).catch('component'),
  needsClarification: z.boolean().catch(false),
  clarificationQuestion: z.string().optional(),
  shouldGenerateCode: z.boolean().catch(true),
});

