  productSummary: z.string().catch(''),
  coreFeatures: z.array(z.string()).catch([]),
  userFlow: z.array(z.string()).catch([]),
  uiSections: z.array(z.string()).catch([]),
  designStyle: z.string().catch(''),
  targetAudience: z.string().catch(''),
